import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Skip Navigation', () => {
  it('renders the skip link', () => {
    render(<App />);
    expect(screen.getByTestId('skip-link')).toBeInTheDocument();
  });

  it('skip link has correct href', () => {
    render(<App />);
    const link = screen.getByTestId('skip-link');
    expect(link).toHaveAttribute('href', '#main-content');
  });

  it('skip link has text content', () => {
    render(<App />);
    const link = screen.getByTestId('skip-link');
    expect(link.textContent?.toLowerCase()).toContain('skip');
  });

  it('main content has tabIndex for focus', () => {
    render(<App />);
    const main = screen.getByTestId('main-content');
    expect(main).toHaveAttribute('tabindex', '-1');
  });

  it('skip link is visually hidden by default', () => {
    render(<App />);
    const link = screen.getByTestId('skip-link');
    const style = window.getComputedStyle(link);
    // Should be positioned off-screen or clipped
    expect(style.position).toBe('absolute');
  });

  it('clicking the skip link moves focus to main', () => {
    render(<App />);
    const link = screen.getByTestId('skip-link');
    fireEvent.click(link);
    // The main element should be focusable
    const main = screen.getByTestId('main-content');
    expect(main).toHaveAttribute('id', 'main-content');
  });
});

